/**
 * Fixes the adaptive icon XMLs generated by @capacitor/assets.
 * The tool generates <background> with @mipmap/ic_launcher_background which
 * doesn't exist — this replaces it with the @color/ic_launcher_background
 * that is already defined in res/values/ic_launcher_background.xml.
 */
import { writeFileSync } from 'fs';
import { resolve, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const anydpiDir = resolve(__dirname, '../android/app/src/main/res/mipmap-anydpi-v26');

const xml = `<?xml version="1.0" encoding="utf-8"?>
<adaptive-icon xmlns:android="http://schemas.android.com/apk/res/android">
    <background android:drawable="@color/ic_launcher_background"/>
    <foreground>
        <inset android:drawable="@mipmap/ic_launcher_foreground" android:inset="16.7%" />
    </foreground>
</adaptive-icon>
`;

writeFileSync(resolve(anydpiDir, 'ic_launcher.xml'), xml);
writeFileSync(resolve(anydpiDir, 'ic_launcher_round.xml'), xml);
console.log('✓ Adaptive icon XMLs fixed');
